describe('parseField — P2 unusual valid patterns', () => {
  test('단일 값 목록: 5', () => {
    const result = parseField('5', 0, 59)
    expect(result).toEqual([5])
  })

  test('연속 범위의 끝점: 0-0', () => {
    const result = parseField('0-0', 0, 59)
    expect(result).toEqual([0])
  })

  test('스텝이 범위와 같음: 1-3/3', () => {
    const result = parseField('1-3/3', 0, 59)
    expect(result).toEqual([1])
  })

  test('큰 스텝: */59 분 필드', () => {
    const result = parseField('*/59', 0, 59)
    expect(result).toEqual([0, 59])
  })

  test('전체 범위 스텝: 0-59/30', () => {
    const result = parseField('0-59/30', 0, 59)
    expect(result).toEqual([0, 30])
  })
})

// ============================================================
// P2: getNextCronDate — yearly boundary
// ============================================================
describe('getNextCronDate — P2 yearly boundary', () => {
  test('12월 31일에서 연도 전환', () => {
    const after = new Date('2026-12-31T23:58:00Z')
    const next = getNextCronDate('0 9 * * *', after)
    expect(next.getUTCFullYear()).toBe(2027)
    expect(next.getUTCMonth()).toBe(0) // January
    expect(next.getUTCHours()).toBe(9)
  })

  test('윤년 2월 29일 (2028)', () => {
    const after = new Date('2028-02-28T23:00:00Z')
    const next = getNextCronDate('0 9 29 * *', after)
    expect(next.getUTCDate()).toBe(29)
    expect(next.getUTCMonth()).toBe(1) // February
  })
})

